1	package docprose
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/json"
7		"fmt"
8		"os/exec"
9		"sort"
10		"strings"
11	)
12	
13	const SupportedValeVersion = "vale version 3.13.0"
14	
15	// ValeAlert is the raw alert shape returned by Vale JSON output before DDx
16	// normalizes it into user-facing prose findings.
17	type ValeAlert struct {
18		File     string
19		Check    string
20		Line     int
21		Span     [2]int
22		Severity string
23		Message  string
24		Match    string
25	}
26	
27	// ValeDiagnosticKind classifies runner failures that DDx wants to surface as
28	// prose-checker diagnostics instead of generic execution errors.
29	type ValeDiagnosticKind string
30	
31	const (
32		ValeDiagnosticMissing     ValeDiagnosticKind = "missing"
33		ValeDiagnosticUnsupported ValeDiagnosticKind = "unsupported"
34	)
35	
36	// ValeDiagnosticError reports missing or unsupported Vale installations.
37	type ValeDiagnosticError struct {
38		Kind    ValeDiagnosticKind
39		Path    string
40		Version string
41		Message string
42	}
43	
44	func (e *ValeDiagnosticError) Error() string {
45		return e.Message
46	}
47	
48	// ValeRunner invokes the pinned Vale binary using a temporary DDx-generated
49	// configuration and parses Vale's JSON output into raw alerts.
50	type ValeRunner struct{}
51	
52	func NewValeRunner() *ValeRunner {
53		return &ValeRunner{}
54	}
55	
56	// Findings runs Vale against the provided paths and returns raw alerts.
57	func (r *ValeRunner) Findings(ctx context.Context, settings Settings, paths ...string) ([]ValeAlert, error) {
58		if len(paths) == 0 {
59			return nil, fmt.Errorf("vale runner requires at least one path")
60		}
61	
62		binary, err := exec.LookPath("vale")
63		if err != nil {
64			return nil, &ValeDiagnosticError{
65				Kind:    ValeDiagnosticMissing,
66				Message: "Vale prose checker is not installed or is not on PATH",
67			}
68		}
69	
70		expectedVersion := expectedValeVersion(settings)
71	
72		versionCmd := exec.CommandContext(ctx, binary, "--version")
73		versionOutput, err := versionCmd.CombinedOutput()
74		version := strings.TrimSpace(string(versionOutput))
75		if err != nil || version != expectedVersion {
76			msg := fmt.Sprintf(
77				"Vale prose checker did not report a supported version; expected %q",
78				expectedVersion,
79			)
80			if version != "" {
81				msg += fmt.Sprintf("; got %q", version)
82			}
83			if err != nil {
84				msg += fmt.Sprintf("; error: %v", err)
85			}
86			return nil, &ValeDiagnosticError{
87				Kind:    ValeDiagnosticUnsupported,
88				Path:    binary,
89				Version: version,
90				Message: msg,
91			}
92		}
93	
94		tempCfg, err := NewTempValeConfig(settings)
95		if err != nil {
96			return nil, err
97		}
98		defer tempCfg.Cleanup()
99	
100		args := []string{"--config", tempCfg.INIPath(), "--output=JSON", "--no-global"}
101		args = append(args, paths...)
102	
103		cmd := exec.CommandContext(ctx, binary, args...)
104		var stdout bytes.Buffer
105		var stderr bytes.Buffer
106		cmd.Stdout = &stdout
107		cmd.Stderr = &stderr
108	
109		runErr := cmd.Run()
110		alerts, parseErr := parseValeAlertsJSON(stdout.Bytes())
111		if parseErr != nil {
112			return nil, parseErr
113		}
114		if runErr != nil {
115			if exitErr, ok := runErr.(*exec.ExitError); ok && exitErr.ExitCode() == 1 {
116				return alerts, nil
117			}
118			if msg := strings.TrimSpace(stderr.String()); msg != "" {
119				return nil, fmt.Errorf("vale run failed: %w: %s", runErr, msg)
120			}
121			return nil, fmt.Errorf("vale run failed: %w", runErr)
122		}
123	
124		return alerts, nil
125	}
126	
127	type valeJSONAlert struct {
128		Path     string `json:"Path"`
129		Check    string `json:"Check"`
130		Line     int    `json:"Line"`
131		Span     []int  `json:"Span"`
132		Severity string `json:"Severity"`
133		Message  string `json:"Message"`
134		Match    string `json:"Match"`
135	}
136	
137	type valeJSONFile struct {
138		Path   string          `json:"Path"`
139		Alerts []valeJSONAlert `json:"Alerts"`
140	}
141	
142	type valeJSONFiles struct {
143		Files []valeJSONFile `json:"Files"`
144	}
145	
146	func parseValeAlertsJSON(data []byte) ([]ValeAlert, error) {
147		data = bytes.TrimSpace(data)
148		if len(data) == 0 {
149			return nil, nil
150		}
151	
152		if alerts, ok, err := parseValeAlertMap(data); err != nil {
153			return nil, err
154		} else if ok {
155			return alerts, nil
156		}
157	
158		if alerts, ok, err := parseValeFilesShape(data); err != nil {
159			return nil, err
160		} else if ok {
161			return alerts, nil
162		}
163	
164		return nil, fmt.Errorf("parse vale JSON output: unsupported shape")
165	}
166	
167	func parseValeAlertMap(data []byte) ([]ValeAlert, bool, error) {
168		var raw map[string][]valeJSONAlert
169		if err := json.Unmarshal(data, &raw); err != nil {
170			return nil, false, nil
171		}
172		alerts := make([]ValeAlert, 0, len(raw))
173		for file, items := range raw {
174			for _, item := range items {
175				alert, err := normalizeValeAlert(file, item)
176				if err != nil {
177					return nil, false, err
178				}
179				alerts = append(alerts, alert)
180			}
181		}
182		sortValeAlerts(alerts)
183		return alerts, true, nil
184	}
185	
186	func parseValeFilesShape(data []byte) ([]ValeAlert, bool, error) {
187		var raw valeJSONFiles
188		if err := json.Unmarshal(data, &raw); err != nil {
189			return nil, false, nil
190		}
191		if len(raw.Files) == 0 {
192			return nil, true, nil
193		}
194	
195		alerts := make([]ValeAlert, 0)
196		for _, file := range raw.Files {
197			for _, item := range file.Alerts {
198				alert, err := normalizeValeAlert(file.Path, item)
199				if err != nil {
200					return nil, false, err
201				}
202				alerts = append(alerts, alert)
203			}
204		}
205		sortValeAlerts(alerts)
206		return alerts, true, nil
207	}
208	
209	func normalizeValeAlert(file string, item valeJSONAlert) (ValeAlert, error) {
210		span := [2]int{}
211		switch len(item.Span) {
212		case 0:
213			span = [2]int{}
214		case 1:
215			span[0] = item.Span[0]
216		case 2:
217			span[0] = item.Span[0]
218			span[1] = item.Span[1]
219		default:
220			span[0] = item.Span[0]
221			span[1] = item.Span[1]
222		}
223	
224		if file == "" {
225			file = strings.TrimSpace(item.Path)
226		}
227		if file == "" {
228			return ValeAlert{}, fmt.Errorf("parse vale JSON output: missing file path")
229		}
230		if item.Check == "" {
231			return ValeAlert{}, fmt.Errorf("parse vale JSON output: missing check for %s:%d", file, item.Line)
232		}
233		if item.Severity == "" {
234			return ValeAlert{}, fmt.Errorf("parse vale JSON output: missing severity for %s:%d", file, item.Line)
235		}
236		if item.Message == "" {
237			return ValeAlert{}, fmt.Errorf("parse vale JSON output: missing message for %s:%d", file, item.Line)
238		}
239		if item.Match == "" {
240			return ValeAlert{}, fmt.Errorf("parse vale JSON output: missing match for %s:%d", file, item.Line)
241		}
242	
243		return ValeAlert{
244			File:     file,
245			Check:    item.Check,
246			Line:     item.Line,
247			Span:     span,
248			Severity: item.Severity,
249			Message:  item.Message,
250			Match:    item.Match,
251		}, nil
252	}
253	
254	func sortValeAlerts(alerts []ValeAlert) {
255		sort.SliceStable(alerts, func(i, j int) bool {
256			if alerts[i].File != alerts[j].File {
257				return alerts[i].File < alerts[j].File
258			}
259			if alerts[i].Line != alerts[j].Line {
260				return alerts[i].Line < alerts[j].Line
261			}
262			if alerts[i].Span[0] != alerts[j].Span[0] {
263				return alerts[i].Span[0] < alerts[j].Span[0]
264			}
265			if alerts[i].Span[1] != alerts[j].Span[1] {
266				return alerts[i].Span[1] < alerts[j].Span[1]
267			}
268			if alerts[i].Check != alerts[j].Check {
269				return alerts[i].Check < alerts[j].Check
270			}
271			if alerts[i].Severity != alerts[j].Severity {
272				return alerts[i].Severity < alerts[j].Severity
273			}
274			if alerts[i].Message != alerts[j].Message {
275				return alerts[i].Message < alerts[j].Message
276			}
277			return alerts[i].Match < alerts[j].Match
278		})
279	}
280	
281	func expectedValeVersion(settings Settings) string {
282		version := strings.TrimSpace(settings.Vale.Version)
283		if version == "" {
284			return SupportedValeVersion
285		}
286		if strings.HasPrefix(version, "vale ") {
287			return version
288		}
289		return "vale version " + version
290	}
