1	package docprose
2	
3	import (
4		"fmt"
5		"regexp"
6		"strings"
7		"unicode"
8	)
9	
10	var inlineCodePattern = regexp.MustCompile("`[^`]*`")
11	var negationSectionHeadingPattern = regexp.MustCompile(`(?i)^(?:what .+ is not|non-?goals?|out of scope|anti-?patterns?)$`)
12	var positiveCopulaPattern = regexp.MustCompile(`(?i)\b(?:is|are|stays|remains)\s+(?:a|an|the\s+)?[[:alpha:]][[:alnum:]_-]*(?:\s+[[:alpha:]][[:alnum:]_-]*){0,4}`)
13	var negationCopulaPattern = regexp.MustCompile(`(?i)\b(?:is|are|stays|remains)\b.*\bnot\b`)
14	
15	type Mode string
16	
17	const (
18		ModeTechnical Mode = "technical"
19		ModePlanning  Mode = "planning"
20		ModePublic    Mode = "public"
21	)
22	
23	type Checker struct {
24		mode       Mode
25		rules      []ruleSpec
26		vocabulary Vocabulary
27	}
28	
29	type lineContext struct {
30		suppressNegation bool
31	}
32	
33	func NewChecker(mode Mode, vocabulary Vocabulary) (*Checker, error) {
34		if mode == "" {
35			mode = ModeTechnical
36		}
37		rules, err := loadRulePack(string(mode))
38		if err != nil {
39			return nil, err
40		}
41		defaultVocab, err := loadDefaultVocabulary()
42		if err != nil {
43			return nil, err
44		}
45		if len(vocabulary.Accept) == 0 {
46			vocabulary.Accept = defaultVocab.Accept
47		}
48		if len(vocabulary.Reject) == 0 {
49			vocabulary.Reject = defaultVocab.Reject
50		}
51		return &Checker{
52			mode:       mode,
53			rules:      rules,
54			vocabulary: vocabulary,
55		}, nil
56	}
57	
58	func (c *Checker) Findings(file, text string) []Finding {
59		var findings []Finding
60		lines := strings.Split(text, "\n")
61		inFrontmatter := false
62		inFence := false
63		fenceMarker := ""
64		seenContent := false
65		negationSuppressed := false
66	
67		for idx, raw := range lines {
68			lineNo := idx + 1
69			trimmed := strings.TrimSpace(raw)
70			if trimmed == "" {
71				continue
72			}
73			if !seenContent && trimmed == "---" {
74				inFrontmatter = true
75				seenContent = true
76				continue
77			}
78			seenContent = true
79	
80			if inFrontmatter {
81				if trimmed == "---" {
82					inFrontmatter = false
83				}
84				continue
85			}
86	
87			if isFenceLine(trimmed) {
88				if inFence {
89					if fenceMarker != "" && strings.HasPrefix(trimmed, fenceMarker) {
90						inFence = false
91						fenceMarker = ""
92					}
93					continue
94				}
95				inFence = true
96				fenceMarker = fenceDelimiter(trimmed)
97				continue
98			}
99			if inFence {
100				continue
101			}
102	
103			if level, heading, ok := markdownHeading(trimmed); ok {
104				if level == 2 || level == 3 {
105					negationSuppressed = negationSectionHeadingPattern.MatchString(heading)
106				}
107				continue
108			}
109	
110			line := stripInlineCode(raw)
111			line = strings.TrimSpace(line)
112			if line == "" || isMarkdownStructureLine(line) {
113				continue
114			}
115	
116			ctx := lineContext{suppressNegation: negationSuppressed}
117			for _, rule := range c.rules {
118				if rule.Kind == "negation_predicate" {
119					if matchesRule(line, rule, ctx) {
120						findings = append(findings, Finding{
121							File:          file,
122							Line:          lineNo,
123							RuleID:        rule.ID,
124							Severity:      rule.Severity,
125							Rationale:     rule.Rationale,
126							SuggestedEdit: rule.SuggestedEdit,
127						})
128					}
129					continue
130				}
131				if rule.Kind == "repeated_opening" {
132					if repeatedOpeningKey(line) != "" {
133						findings = append(findings, Finding{
134							File:          file,
135							Line:          lineNo,
136							RuleID:        rule.ID,
137							Severity:      rule.Severity,
138							Rationale:     rule.Rationale,
139							SuggestedEdit: rule.SuggestedEdit,
140						})
141					}
142					continue
143				}
144				if matchesRule(line, rule, ctx) {
145					findings = append(findings, Finding{
146						File:          file,
147						Line:          lineNo,
148						RuleID:        rule.ID,
149						Severity:      rule.Severity,
150						Rationale:     rule.Rationale,
151						SuggestedEdit: rule.SuggestedEdit,
152					})
153				}
154			}
155	
156			findings = append(findings, c.vocabularyFindings(file, lineNo, line)...)
157		}
158	
159		return findings
160	}
161	
162	func (c *Checker) vocabularyFindings(file string, lineNo int, line string) []Finding {
163		var findings []Finding
164		lower := strings.ToLower(line)
165		for _, reject := range c.vocabulary.Reject {
166			if reject == "" {
167				continue
168			}
169			if !containsWord(lower, reject) {
170				continue
171			}
172			if c.termAccepted(reject) {
173				continue
174			}
175			findings = append(findings, Finding{
176				File:          file,
177				Line:          lineNo,
178				RuleID:        "prose.vocabulary.reject",
179				Severity:      "warning",
180				Rationale:     fmt.Sprintf("The vocabulary term %q is discouraged in default prose because it is too generic.", reject),
181				SuggestedEdit: fmt.Sprintf("Replace %q with the project-specific term or concrete noun that names the actual concept.", reject),
182			})
183		}
184		return findings
185	}
186	
187	func (c *Checker) termAccepted(term string) bool {
188		for _, accept := range c.vocabulary.Accept {
189			if accept == "" {
190				continue
191			}
192			if strings.EqualFold(strings.TrimSpace(accept), strings.TrimSpace(term)) {
193				return true
194			}
195		}
196		return false
197	}
198	
199	func matchesRule(line string, rule ruleSpec, ctx lineContext) bool {
200		if isMarkdownStructureLine(line) {
201			return false
202		}
203		switch rule.ID {
204		case "prose.claim.unsupported":
205			return unsupportedClaim(line)
206		case "prose.ai_slop.polish":
207			return aiSlop(line)
208		case "prose.filler.transition":
209			return fillerTransition(line)
210		case "prose.specificity.actor_action":
211			return missingActorAction(line)
212		case "prose.cost.filler":
213			return tokenCost(line)
214		case "prose.structure.repeated_opening":
215			return repeatedOpeningKey(line) != ""
216		}
217		if rule.Kind == "negation_predicate" {
218			if ctx.suppressNegation {
219				return false
220			}
221			return definitionByNegation(line)
222		}
223		if len(rule.ContainsAny) == 0 {
224			return false
225		}
226		lower := strings.ToLower(line)
227		for _, phrase := range rule.ContainsAny {
228			if phrase == "" {
229				continue
230			}
231			if strings.Contains(lower, strings.ToLower(phrase)) {
232				return true
233			}
234		}
235		return false
236	}
237	
238	func isMarkdownStructureLine(line string) bool {
239		trimmed := strings.TrimSpace(line)
240		if trimmed == "" {
241			return true
242		}
243		if strings.HasPrefix(trimmed, "#") || strings.HasPrefix(trimmed, "---") {
244			return true
245		}
246		if strings.HasPrefix(trimmed, "|") && strings.HasSuffix(trimmed, "|") {
247			return true
248		}
249		if strings.Contains(trimmed, ".md") || strings.Contains(trimmed, ".yaml") || strings.Contains(trimmed, ".json") {
250			return true
251		}
252		if strings.HasPrefix(trimmed, "- ") && len(strings.Fields(trimmed)) <= 8 {
253			return true
254		}
255		return false
256	}
257	
258	func unsupportedClaim(line string) bool {
259		lower := strings.ToLower(line)
260		if containsAny(lower, []string{
261			"robust",
262			"comprehensive",
263			"industry-leading",
264			"world-class",
265			"best-in-class",
266			"cutting-edge",
267		}) {
268			return true
269		}
270		if unsupportedComprehensiveClaim(lower) {
271			return true
272		}
273		return containsAny(lower, []string{
274			"experience for everyone",
275			"path forward",
276			"broadly useful",
277			"easy to adopt",
278		})
279	}
280	
281	func unsupportedComprehensiveClaim(lower string) bool {
282		if !strings.Contains(lower, "comprehensive") {
283			return false
284		}
285		return containsAny(lower, []string{
286			"comprehensive prd",
287			"comprehensive implementation plan",
288			"comprehensive plan",
289			"comprehensive checklist",
290			"comprehensive checklists",
291			"comprehensive tests",
292			"comprehensive documentation",
293		})
294	}
295	
296	func aiSlop(line string) bool {
297		lower := strings.ToLower(line)
298		return containsAny(lower, []string{
299			"complex problems",
300			"powerful commands",
301			"powerful automation",
302			"sophisticated autonomous",
303			"sophisticated control flow",
304			"sophisticated multi-agent",
305			"productive ways",
306			"true power",
307		})
308	}
309	
310	func fillerTransition(line string) bool {
311		lower := strings.ToLower(line)
312		return containsAny(lower, []string{
313			"to be clear",
314			"first, we should note",
315			"in conclusion",
316			"it is important to note",
317			"for clarity",
318			"that said",
319		})
320	}
321	
322	func missingActorAction(line string) bool {
323		lower := strings.ToLower(line)
324		return containsAny(lower, []string{"enables", "supports", "streamlines"})
325	}
326	
327	func tokenCost(line string) bool {
328		lower := strings.ToLower(line)
329		if containsAny(lower, []string{
330			"very important",
331			"in order to",
332			"effectively",
333			"begin to",
334			"make the experience better",
335		}) {
336			return true
337		}
338		return countMatches(lower, []string{"robust", "comprehensive", "smooth", "elegant", "excited", "high"}) >= 2
339	}
340	
341	func containsAny(s string, needles []string) bool {
342		for _, needle := range needles {
343			if strings.Contains(s, needle) {
344				return true
345			}
346		}
347		return false
348	}
349	
350	func countMatches(s string, needles []string) int {
351		var count int
352		for _, needle := range needles {
353			if strings.Contains(s, needle) {
354				count++
355			}
356		}
357		return count
358	}
359	
360	func countWords(s string) int {
361		return len(strings.Fields(s))
362	}
363	
364	func markdownHeading(line string) (level int, heading string, ok bool) {
365		if !strings.HasPrefix(line, "#") {
366			return 0, "", false
367		}
368		level = 0
369		for level < len(line) && line[level] == '#' {
370			level++
371		}
372		if level < 2 || level > 3 {
373			return 0, "", false
374		}
375		if level >= len(line) || line[level] != ' ' {
376			return 0, "", false
377		}
378		heading = strings.TrimSpace(line[level+1:])
379		heading = strings.TrimRightFunc(heading, func(r rune) bool {
380			return r == '#' || unicode.IsSpace(r)
381		})
382		heading = strings.TrimSpace(heading)
383		return level, heading, heading != ""
384	}
385	
386	func definitionByNegation(line string) bool {
387		for _, sentence := range sentenceFragments(line) {
388			if sentenceDefinitionByNegation(sentence) {
389				return true
390			}
391		}
392		return false
393	}
394	
395	func sentenceFragments(line string) []string {
396		var fragments []string
397		rest := strings.TrimSpace(line)
398		for rest != "" {
399			head, tail, ok := cutSentence(rest)
400			if !ok {
401				fragments = append(fragments, rest)
402				break
403			}
404			fragments = append(fragments, head)
405			rest = strings.TrimSpace(tail)
406		}
407		return fragments
408	}
409	
410	func sentenceDefinitionByNegation(sentence string) bool {
411		sentence = strings.TrimSpace(sentence)
412		if sentence == "" {
413			return false
414		}
415		if !negationCopulaPattern.MatchString(sentence) {
416			return false
417		}
418		if positivePredicateAfterNegation(sentence) {
419			return false
420		}
421		if positivePredicateBeforeSemicolon(sentence) {
422			return false
423		}
424		return true
425	}
426	
427	func positivePredicateAfterNegation(sentence string) bool {
428		lower := strings.ToLower(sentence)
429		idx := strings.Index(lower, " not ")
430		if idx == -1 {
431			return false
432		}
433		tail := strings.TrimSpace(sentence[idx+len(" not "):])
434		return positiveCopulaPattern.MatchString(tail)
435	}
436	
437	func positivePredicateBeforeSemicolon(sentence string) bool {
438		idx := strings.IndexAny(sentence, ";:")
439		if idx == -1 {
440			return false
441		}
442		head := strings.TrimSpace(sentence[:idx])
443		tail := strings.TrimSpace(sentence[idx+1:])
444		if !positiveCopulaPattern.MatchString(head) {
445			return false
446		}
447		return negationCopulaPattern.MatchString(tail)
448	}
449	
450	func stripInlineCode(line string) string {
451		return inlineCodePattern.ReplaceAllString(line, "")
452	}
453	
454	func isFenceLine(trimmed string) bool {
455		return strings.HasPrefix(trimmed, "```") || strings.HasPrefix(trimmed, "~~~")
456	}
457	
458	func fenceDelimiter(trimmed string) string {
459		if strings.HasPrefix(trimmed, "```") {
460			return "```"
461		}
462		if strings.HasPrefix(trimmed, "~~~") {
463			return "~~~"
464		}
465		return ""
466	}
467	
468	func repeatedOpeningKey(line string) string {
469		first, rest, ok := cutSentence(line)
470		if !ok {
471			return ""
472		}
473		second, _, ok := cutSentence(rest)
474		if !ok {
475			return ""
476		}
477		first = normalizeSentence(first)
478		second = normalizeSentence(second)
479		if first == "" || first != second {
480			return ""
481		}
482		return first
483	}
484	
485	func cutSentence(s string) (head, tail string, ok bool) {
486		s = strings.TrimSpace(s)
487		if s == "" {
488			return "", "", false
489		}
490		for i, r := range s {
491			if r == '.' || r == '!' || r == '?' {
492				return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
493			}
494		}
495		return "", "", false
496	}
497	
498	func normalizeSentence(s string) string {
499		s = strings.ToLower(strings.TrimSpace(s))
500		s = strings.TrimFunc(s, func(r rune) bool {
501			return unicode.IsPunct(r) || unicode.IsSpace(r)
502		})
503		s = strings.Join(strings.Fields(s), " ")
504		return s
505	}
506	
507	func containsWord(haystack, needle string) bool {
508		needle = strings.TrimSpace(needle)
509		if needle == "" {
510			return false
511		}
512		pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
513		return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
514	}
