289	func containsAll(got []string, want []string) bool {
290		m := make(map[string]bool, len(got))
291		for _, s := range got {
292			m[s] = true
293		}
294		for _, s := range want {
295			if !m[s] {
296				return false
297			}
298		}
299		return true
300	}
